from __future__ import annotations

import importlib
import sys

runtime = sys.modules["cookimport.cli_support"]

# Snapshot the already-initialized root support namespace so the moved
# benchmark helpers can keep their unqualified references.
globals().update(
    {
        name: value
        for name, value in vars(runtime).items()
        if not name.startswith("__")
    }
)

for _module_name in (
    "bench_oracle",
    "bench_artifacts",
    "bench_cache",
    "bench_all_method",
    "bench_single_book",
    "bench_single_profile",
):
    _module = importlib.import_module(f"{__package__}.{_module_name}")
    globals().update(
        {
            name: value
            for name, value in vars(_module).items()
            if not name.startswith("__")
        }
    )

